script:
frappe.ui.form.on("Opportunity", {
    refresh(frm) {
        // Wait a moment for ERPNext to build the menu
        setTimeout(() => {
            frm.page.add_menu_item("Survey", () => {

                let survey_values = {
                    opportunity: frm.doc.name,
                    contact_person: frm.doc.contact_person,
                    contact_email: frm.doc.contact_email
                };

                if (frm.doc.opportunity_from === "Customer") {
                    survey_values.customer = frm.doc.party_name;
                    survey_values.customer_name = frm.doc.customer_name;
                }

                if (frm.doc.opportunity_from === "Lead") {
                    survey_values.customer = "";
                    survey_values.customer_name = frm.doc.customer_name;
                }

                frappe.new_doc("Survey", survey_values);
            });
        }, 500);  // ⬅️ Delay ensures Create menu is fully loaded
    }
});

frappe.ui.form.on("Survey", {
    refresh: function(frm) {
        if (!frm.doc.__islocal) {
            frm.add_custom_button("Quotation", () => {
                frappe.call({
                    method: "grand_renovations_app.overrides.survey.create_quotation_from_survey",
                    args: {
                        survey_name: frm.doc.name
                    },
                    callback: function(r) {
                        if (r.message) {
                            frappe.model.sync(r.message);
                            frappe.set_route("Form", "Quotation", r.message.name);
                        }
                    }
                });
            }, __("Create"));
        }
    }
});

frappe.ui.form.on("Survey", {
    refresh(frm) {
        if (!frm.doc.lead || !frm.doc.opportunity) return;
        frm.trigger("render_attachments");
    },

    // ----------------------------------
    // Render Attachments (DEDUPLICATED)
    // ----------------------------------
    render_attachments(frm) {
        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "File",
                filters: [
                    ["attached_to_doctype", "in", ["Lead", "Opportunity"]],
                    ["attached_to_name", "in", [frm.doc.lead, frm.doc.opportunity]]
                ],
                fields: ["file_name", "file_url"],
                order_by: "creation desc"
            },
            callback(r) {
                let html = `
                    <div style="margin-bottom:10px;">
                        <button class="btn btn-xs btn-primary upload-survey-attachment">
                            + Add Attachment
                        </button>
                    </div>
                `;

                if (!r.message || !r.message.length) {
                    html += `<em>No attachments found.</em>`;
                    frm.fields_dict.custom_lead_files_html.$wrapper.html(html);

                    // Bind button even when empty
                    frm.fields_dict.custom_lead_files_html.$wrapper
                        .find(".upload-survey-attachment")
                        .on("click", () => frm.trigger("upload_attachment"));
                    return;
                }

                // Deduplicate by file_url
                const seen = new Set();

                r.message.forEach(file => {
                    if (seen.has(file.file_url)) return;
                    seen.add(file.file_url);

                    html += `
                        <div style="margin-bottom:6px; display:flex; align-items:center; gap:6px;">
                            📎 <a href="${file.file_url}" target="_blank">
                                ${file.file_name}
                            </a>
                            <button
                                class="btn btn-xs btn-secondary remove-attachment"
                                style="padding:2px 6px; font-size:11px;"
                                data-file-url="${file.file_url}">
                                Remove
                            </button>
                        </div>
                    `;
                });

                frm.fields_dict.custom_lead_files_html.$wrapper.html(html);

                const wrapper = frm.fields_dict.custom_lead_files_html.$wrapper;

                wrapper.find(".upload-survey-attachment")
                    .on("click", () => frm.trigger("upload_attachment"));

                wrapper.find(".remove-attachment")
                    .on("click", function () {
                        const file_url = $(this).data("file-url");
                        frm.events.remove_attachment(frm, file_url);
                    });
            }
        });
    },







    // ----------------------------------
    // Upload & Attach (WITH QUOTATION SYNC)
    // ----------------------------------
    upload_attachment(frm) {
        new frappe.ui.FileUploader({
            allow_multiple: true,
            on_success(file) {
                frappe.call({
                    method: "frappe.client.get",
                    args: {
                        doctype: "File",
                        name: file.name
                    },
                    callback(r) {
                        const uploaded = r.message;
                        const inserts = [];

                        // 1️⃣ Attach to Opportunity
                        inserts.push(
                            new Promise(resolve => {
                                frappe.call({
                                    method: "frappe.client.insert",
                                    args: {
                                        doc: {
                                            doctype: "File",
                                            file_name: uploaded.file_name,
                                            file_url: uploaded.file_url,
                                            is_private: uploaded.is_private,
                                            attached_to_doctype: "Opportunity",
                                            attached_to_name: frm.doc.opportunity
                                        }
                                    },
                                    callback: () => resolve()
                                });
                            })
                        );

                        // 2️⃣ Attach to Lead
                        inserts.push(
                            new Promise(resolve => {
                                frappe.call({
                                    method: "frappe.client.insert",
                                    args: {
                                        doc: {
                                            doctype: "File",
                                            file_name: uploaded.file_name,
                                            file_url: uploaded.file_url,
                                            is_private: uploaded.is_private,
                                            attached_to_doctype: "Lead",
                                            attached_to_name: frm.doc.lead
                                        }
                                    },
                                    callback: () => resolve()
                                });
                            })
                        );

                        // 3️⃣ Attach to all Quotations linked to this Survey
                        frappe.call({
                            method: "frappe.client.get_list",
                            args: {
                                doctype: "Quotation",
                                filters: {
                                    custom_survey: frm.doc.name
                                },
                                fields: ["name"]
                            },
                            callback(quot_r) {
                                if (quot_r.message && quot_r.message.length) {
                                    quot_r.message.forEach(quot => {
                                        inserts.push(
                                            new Promise(resolve => {
                                                frappe.call({
                                                    method: "frappe.client.insert",
                                                    args: {
                                                        doc: {
                                                            doctype: "File",
                                                            file_name: uploaded.file_name,
                                                            file_url: uploaded.file_url,
                                                            is_private: uploaded.is_private,
                                                            attached_to_doctype: "Quotation",
                                                            attached_to_name: quot.name
                                                        }
                                                    },
                                                    callback: () => resolve()
                                                });
                                            })
                                        );
                                    });
                                }

                                // Wait for ALL inserts to complete
                                Promise.all(inserts).then(() => {
                                    frappe.show_alert({
                                        message: "Attachment synced to Lead, Opportunity & Quotation",
                                        indicator: "green"
                                    });

                                    // Refresh UI only AFTER inserts complete
                                    frm.trigger("render_attachments");
                                });
                            }
                        });
                    }
                });
            }
        });
    },

    // ----------------------------------
    // Remove Attachment (FROM EVERYWHERE)
    // ----------------------------------
    remove_attachment(frm, file_url) {
        frappe.confirm("Remove this attachment from everywhere (Lead, Opportunity & Quotation)?", () => {
            frappe.call({
                method: "frappe.client.get_list",
                args: {
                    doctype: "File",
                    filters: { file_url },
                    fields: ["name"]
                },
                callback(r) {
                    if (!r.message || !r.message.length) return;

                    const deletes = r.message.map(file => {
                        return new Promise(resolve => {
                            frappe.call({
                                method: "frappe.client.delete",
                                args: {
                                    doctype: "File",
                                    name: file.name
                                },
                                callback: () => resolve()
                            });
                        });
                    });

                    Promise.all(deletes).then(() => {
                        frappe.show_alert({
                            message: "Attachment removed from everywhere",
                            indicator: "orange"
                        });

                        // Refresh UI only AFTER deletes complete
                        frm.trigger("render_attachments");
                    });
                }
            });
        });
    }
});

frappe.ui.form.on("Quotation", {
    onload(frm) {
        // Only when created from Survey
        if (frm.doc.__islocal && frm.doc.custom_survey) {

            frappe.call({
                method: "frappe.client.get",
                args: {
                    doctype: "Survey",
                    name: frm.doc.custom_survey
                },
                callback(r) {
                    if (!r.message) return;

                    // 1️⃣ Set Opportunity
                    if (r.message.opportunity && !frm.doc.opportunity) {
                        frm.set_value("opportunity", r.message.opportunity);
                    }

                    // 2️⃣ Set Lead
                    if (r.message.lead && !frm.doc.custom_lead) {
                        frm.set_value("custom_lead", r.message.lead);
                    }
                }
            });
        }
    }
});

frappe.ui.form.on("Lead", {
    refresh(frm) {
        // Monitor attachment removals
        monitor_attachment_removals(frm);
    }
});

// ----------------------------------
// Monitor Standard Attachment Removals
// ----------------------------------
function monitor_attachment_removals(frm) {
    // Wait for sidebar to load
    setTimeout(() => {
        // Get current attachments
        get_current_attachments(frm);

        // Check for removals every 2 seconds
        if (frm.attachment_check_interval) {
            clearInterval(frm.attachment_check_interval);
        }

        frm.attachment_check_interval = setInterval(() => {
            check_for_removed_attachments(frm);
        }, 2000);
    }, 1000);
}

// ----------------------------------
// Get Current Attachments
// ----------------------------------
function get_current_attachments(frm) {
    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "File",
            filters: {
                attached_to_doctype: "Lead",
                attached_to_name: frm.doc.name
            },
            fields: ["name", "file_url"],
            limit_page_length: 0
        },
        callback(r) {
            frm.previous_attachments = r.message || [];
        }
    });
}

// ----------------------------------
// Check for Removed Attachments
// ----------------------------------
function check_for_removed_attachments(frm) {
    if (!frm.previous_attachments) return;

    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "File",
            filters: {
                attached_to_doctype: "Lead",
                attached_to_name: frm.doc.name
            },
            fields: ["name", "file_url"],
            limit_page_length: 0
        },
        callback(r) {
            const current_attachments = r.message || [];
            const current_urls = current_attachments.map(f => f.file_url);

            // Find removed files
            const removed = frm.previous_attachments.filter(
                prev => !current_urls.includes(prev.file_url)
            );

            if (removed.length > 0) {
                removed.forEach(file => {
                    remove_from_all_doctypes(file.file_url, frm);
                });
            }

            // Update previous attachments
            frm.previous_attachments = current_attachments;
        }
    });
}

// ----------------------------------
// Remove from ALL Doctypes
// ----------------------------------
function remove_from_all_doctypes(file_url, frm) {
    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "File",
            filters: { 
                file_url: file_url,
                attached_to_doctype: ["in", ["Lead", "Opportunity", "Survey", "Quotation"]]
            },
            fields: ["name"],
            limit_page_length: 0
        },
        callback(r) {
            if (!r.message || !r.message.length) return;

            Promise.all(
                r.message.map(f =>
                    frappe.call({
                        method: "frappe.client.delete",
                        args: { 
                            doctype: "File", 
                            name: f.name 
                        }
                    })
                )
            ).then(() => {
                console.log("Attachment removed from all places");
                frappe.show_alert({
                    message: "Attachment removed from Lead, Opportunity, Survey & Quotation",
                    indicator: "orange"
                });
            });
        }
    });
}

// ----------------------------------
// Cleanup interval on form unload
// ----------------------------------
frappe.ui.form.on("Lead", {
    onload(frm) {
        $(window).on('beforeunload', () => {
            if (frm.attachment_check_interval) {
                clearInterval(frm.attachment_check_interval);
            }
        });
    }
});

frappe.ui.form.on("Survey", {

    // ----------------------------------
    // Refresh (ONLY Lead required)
    // ----------------------------------
    refresh(frm) {
        if (!frm.doc.lead) {
            frappe.msgprint("Please link a Lead first");
            return;
        }
        frm.trigger("render_attachments");
    },

    // ----------------------------------
    // Render Attachments
    // ----------------------------------
    render_attachments(frm) {

        const wrapper = frm.fields_dict.custom_lead_files_html?.$wrapper;
        if (!wrapper) return;

        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "File",
                filters: [
                    ["attached_to_doctype", "=", "Lead"],
                    ["attached_to_name", "=", frm.doc.lead]
                ],
                fields: ["file_name", "file_url"],
                order_by: "creation desc"
            },
            callback(r) {

                let html = `
                    <div style="margin-bottom:10px;">
                        <button class="btn btn-xs btn-primary upload-survey-attachment">
                            <i class="fa fa-plus"></i> Add Attachment
                        </button>
                    </div>
                `;

                if (!r.message || !r.message.length) {
                    html += `<em style="color:#888;">No attachments found.</em>`;
                } else {
                    const seen = new Set();

                    r.message.forEach(file => {
                        if (seen.has(file.file_url)) return;
                        seen.add(file.file_url);

                        html += `
                            <div style="margin-bottom:8px; display:flex; align-items:center; gap:8px; padding:6px; background:#f9f9f9; border-radius:4px;">
                                <i class="fa fa-paperclip" style="color:#5e64ff;"></i>
                                <a href="${file.file_url}" target="_blank" style="flex:1; text-decoration:none;">
                                    ${file.file_name}
                                </a>
                                <button
                                    class="btn btn-xs btn-danger remove-attachment"
                                    data-file-url="${file.file_url}">
                                    <i class="fa fa-trash"></i>
                                </button>
                            </div>
                        `;
                    });
                }

                wrapper.html(html);

                // Upload
                wrapper.find(".upload-survey-attachment")
                    .off("click")
                    .on("click", () => frm.trigger("upload_attachment"));

                // Remove (delegated)
                wrapper.off("click", ".remove-attachment");
                wrapper.on("click", ".remove-attachment", function () {
                    frm.trigger("remove_attachment", $(this).data("file-url"));
                });
            }
        });
    },

    // ----------------------------------
    // Upload & Sync (Survey → Lead → Quotation)
    // ----------------------------------
    upload_attachment(frm) {

        new frappe.ui.FileUploader({
            allow_multiple: true,

            on_success(file_doc) {
                frappe.call({
                    method: "frappe.client.get",
                    args: {
                        doctype: "File",
                        name: file_doc.name
                    },
                    callback(r) {
                        if (!r.message) return;

                        const uploaded = r.message;
                        frm.events.sync_attachment_to_all(frm, uploaded);
                    }
                });
            }
        });
    },

    // ----------------------------------
    // Sync Attachment Everywhere
    // ----------------------------------
    sync_attachment_to_all(frm, file_data) {

        const tasks = [];

        // Lead
        tasks.push(
            frm.events.attach_file_to_doc(
                "Lead",
                frm.doc.lead,
                file_data
            )
        );

        // Quotations linked to Survey
        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Quotation",
                filters: { custom_survey: frm.doc.name },
                fields: ["name"]
            },
            callback(r) {

                if (r.message) {
                    r.message.forEach(q => {
                        tasks.push(
                            frm.events.attach_file_to_doc(
                                "Quotation",
                                q.name,
                                file_data
                            )
                        );
                    });
                }

                Promise.all(tasks).then(() => {
                    frappe.show_alert({
                        message: "Attachment synced to Lead & Quotation",
                        indicator: "green"
                    });
                    frm.trigger("render_attachments");
                });
            }
        });
    },

    // ----------------------------------
    // Helper: Attach File
    // ----------------------------------
    attach_file_to_doc(doctype, name, file_data) {
        return frappe.call({
            method: "frappe.client.insert",
            args: {
                doc: {
                    doctype: "File",
                    file_name: file_data.file_name,
                    file_url: file_data.file_url,
                    is_private: file_data.is_private || 0,
                    attached_to_doctype: doctype,
                    attached_to_name: name
                }
            }
        });
    },

    // ----------------------------------
    // Remove Attachment Everywhere
    // ----------------------------------
    remove_attachment(frm, file_url) {

        frappe.confirm(
            "Remove this attachment from Lead & all related Quotations?",
            () => {
                frappe.call({
                    method: "frappe.client.get_list",
                    args: {
                        doctype: "File",
                        filters: { file_url },
                        fields: ["name"]
                    },
                    callback(r) {

                        if (!r.message || !r.message.length) return;

                        Promise.all(
                            r.message.map(f =>
                                frappe.call({
                                    method: "frappe.client.delete",
                                    args: {
                                        doctype: "File",
                                        name: f.name
                                    }
                                })
                            )
                        ).then(() => {
                            frappe.show_alert({
                                message: "Attachment removed everywhere",
                                indicator: "orange"
                            });
                            frm.trigger("render_attachments");
                        });
                    }
                });
            }
        );
    }
});

// ==========================================
// LEAD CLIENT SCRIPT
// Monitors sidebar attachment changes
// ==========================================

frappe.ui.form.on("Lead", {
    refresh(frm) {
        monitor_attachment_changes(frm);
    },

    onload(frm) {
        // Cleanup interval on form unload
        $(window).on('beforeunload', () => {
            if (frm.attachment_check_interval) {
                clearInterval(frm.attachment_check_interval);
            }
        });
    }
});

// ----------------------------------
// Monitor Attachment Changes
// ----------------------------------
function monitor_attachment_changes(frm) {
    setTimeout(() => {
        get_current_attachments(frm);

        if (frm.attachment_check_interval) {
            clearInterval(frm.attachment_check_interval);
        }

        frm.attachment_check_interval = setInterval(() => {
            check_attachment_changes(frm);
        }, 2000);
    }, 1000);
}

// ----------------------------------
// Get Current Attachments
// ----------------------------------
function get_current_attachments(frm) {
    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "File",
            filters: {
                attached_to_doctype: "Lead",
                attached_to_name: frm.doc.name
            },
            fields: ["name", "file_url", "file_name", "is_private"],
            limit_page_length: 0
        },
        callback(r) {
            frm.previous_attachments = r.message || [];
        }
    });
}

// ----------------------------------
// Check for Added or Removed Attachments
// ----------------------------------
function check_attachment_changes(frm) {
    if (!frm.previous_attachments) return;

    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "File",
            filters: {
                attached_to_doctype: "Lead",
                attached_to_name: frm.doc.name
            },
            fields: ["name", "file_url", "file_name", "is_private"],
            limit_page_length: 0
        },
        callback(r) {
            const current = r.message || [];
            const prev_urls = frm.previous_attachments.map(f => f.file_url);
            const curr_urls = current.map(f => f.file_url);

            // Find newly added files
            const added = current.filter(f => !prev_urls.includes(f.file_url));

            // Find removed files
            const removed = frm.previous_attachments.filter(f => !curr_urls.includes(f.file_url));

            if (added.length > 0) {
                added.forEach(file => sync_attachment_to_all(frm, file));
            }

            if (removed.length > 0) {
                removed.forEach(file => remove_attachment_from_all(file.file_url));
            }

            frm.previous_attachments = current;
        }
    });
}

// ----------------------------------
// Sync Attachment to Related Docs
// ----------------------------------
function sync_attachment_to_all(frm, file) {
    const inserts = [];

    // Get linked Opportunity
    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "Opportunity",
            filters: { party_name: frm.doc.name },
            fields: ["name"],
            limit_page_length: 1
        },
        callback(opp_r) {
            if (opp_r.message && opp_r.message.length > 0) {
                const opp_name = opp_r.message[0].name;

                // Add to Opportunity
                inserts.push(create_file_record(file, "Opportunity", opp_name));

                // Get linked Survey
                frappe.call({
                    method: "frappe.client.get_list",
                    args: {
                        doctype: "Survey",
                        filters: { opportunity: opp_name },
                        fields: ["name"]
                    },
                    callback(survey_r) {
                        if (survey_r.message && survey_r.message.length > 0) {
                            survey_r.message.forEach(survey => {
                                inserts.push(create_file_record(file, "Survey", survey.name));
                            });
                        }

                        // Get linked Quotations
                        frappe.call({
                            method: "frappe.client.get_list",
                            args: {
                                doctype: "Quotation",
                                filters: { opportunity: opp_name },
                                fields: ["name"]
                            },
                            callback(quot_r) {
                                if (quot_r.message && quot_r.message.length > 0) {
                                    quot_r.message.forEach(quot => {
                                        inserts.push(create_file_record(file, "Quotation", quot.name));
                                    });
                                }

                                // Execute all inserts
                                Promise.all(inserts).then(() => {
                                    frappe.show_alert({
                                        message: "Attachment synced to all related documents",
                                        indicator: "green"
                                    });
                                });
                            }
                        });
                    }
                });
            }
        }
    });
}

// ----------------------------------
// Remove from All Doctypes
// ----------------------------------
function remove_attachment_from_all(file_url) {
    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "File",
            filters: { 
                file_url: file_url,
                attached_to_doctype: ["in", ["Lead", "Opportunity", "Survey", "Quotation"]]
            },
            fields: ["name"],
            limit_page_length: 0
        },
        callback(r) {
            if (!r.message || !r.message.length) return;

            Promise.all(
                r.message.map(f =>
                    frappe.call({
                        method: "frappe.client.delete",
                        args: { 
                            doctype: "File", 
                            name: f.name 
                        }
                    })
                )
            ).then(() => {
                frappe.show_alert({
                    message: "Attachment removed from all related documents",
                    indicator: "orange"
                });
            });
        }
    });
}

// ----------------------------------
// Helper: Create File Record
// ----------------------------------
function create_file_record(file, doctype, docname) {
    return new Promise(resolve => {
        // Check if file already exists
        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "File",
                filters: {
                    file_url: file.file_url,
                    attached_to_doctype: doctype,
                    attached_to_name: docname
                },
                fields: ["name"]
            },
            callback(check_r) {
                if (check_r.message && check_r.message.length > 0) {
                    resolve(); // Already exists
                    return;
                }

                // Create new file record
                frappe.call({
                    method: "frappe.client.insert",
                    args: {
                        doc: {
                            doctype: "File",
                            file_name: file.file_name,
                            file_url: file.file_url,
                            is_private: file.is_private,
                            attached_to_doctype: doctype,
