            "Decorative Panels",
            "External Cladding Systems",
            "Decorative Paints",
            "Extension",
            "Bathroom",
            "Roofing",
            "General Building",
            "Other"
        ];

        let field_label = frm.fields_dict.project_type.df.label;

        // 🔥 GRID CONTAINER
        let wrapper = $(`
            <div id="product-ui-wrapper" style="margin-bottom:20px;">
                <label class="control-label">${field_label}</label>

                <div id="project-container" style="
                    display:grid;
                    grid-template-columns: repeat(auto-fit, minmax(360px, 1fr));
                    gap:15px;
                    margin-top:10px;
                "></div>

                <button type="button"
                        class="btn btn-xs btn-primary"
                        id="add-project-btn"
                        style="margin-top:15px;">
                    <i class="fa fa-plus"></i> Add Project Type
                </button>
            </div>
        `);

        frm.fields_dict.project_type.$wrapper.before(wrapper);

        let container = $("#project-container");

        function update_value() {
            let values = [];

            container.find(".project-row").each(function() {
                let product = $(this).find("select").val();
                let qty = $(this).find(".qty").text();

                if (product) {
                    values.push(product + ":" + qty);
                }
            });

            frm.set_value("project_type", values.join(", "));
        }

        function create_row(selected = "", qty = 1) {

            let row = $(`
                <div class="project-row" style="
                    padding:12px;
                    background:#f8f9fa;
                    border-radius:8px;
                    border:1px solid #e0e0e0;
                ">
                    <div style="display:flex; justify-content:space-between; align-items:center;">
                        <select class="form-control" style="flex:1;"></select>
                        <button type="button"
                                class="btn btn-xs btn-danger remove"
                                style="margin-left:8px;">✕</button>
                    </div>

                    <div style="margin-top:8px; text-align:center;">
                        <button type="button"
                                class="btn btn-xs btn-default minus">-</button>

                        <span class="qty"
                              style="margin:0 10px; font-weight:600;">${qty}</span>

                        <button type="button"
                                class="btn btn-xs btn-default plus">+</button>
                    </div>
                </div>
            `);

            let select = row.find("select");

            select.append(`<option value="">Select</option>`);

            OPTIONS.forEach(opt => {
                let sel = opt === selected ? "selected" : "";
                select.append(`<option ${sel} value="${opt}">${opt}</option>`);
            });

            select.on("change", function() {
                update_value();
            });

            row.find(".plus").click(function() {
                let current = parseInt(row.find(".qty").text());
                row.find(".qty").text(current + 1);
                update_value();
            });

            row.find(".minus").click(function() {
                let current = parseInt(row.find(".qty").text());
                if (current > 1) {
                    row.find(".qty").text(current - 1);
                    update_value();
                }
            });

            row.find(".remove").click(function() {
                row.remove();
                update_value();
            });

            container.append(row);
        }

        // Load saved values
        if (frm.doc.project_type && frm.doc.project_type.trim() !== "") {
            frm.doc.project_type.split(", ").forEach(entry => {
                let parts = entry.split(":");
                let product = parts[0];
                let qty = parseInt(parts[1]) || 1;
                create_row(product, qty);
            });
        }

        $("#add-project-btn").click(function() {
            create_row();
        });

    }
});

