// ======================================================
// GENERATE CHILD ROWS BASED ON PROJECT TYPE + QTY
// ======================================================
function generate_measurements(frm) {

    frm.clear_table("custom_measurementtable");

    if (!frm.doc.project_type) {
        frm.refresh_field("custom_measurementtable");
        render_measurement_ui(frm);
        return;
    }

    const entries = frm.doc.project_type.split(", ");

    entries.forEach(entry => {

        const [product, qtyStr] = entry.split(":");
        const qty = parseInt(qtyStr) || 1;

        for (let i = 1; i <= qty; i++) {

            const row = frm.add_child("custom_measurementtable");

            row.project_type = product;
            row.item_no = i;
        }
    });

    frm.refresh_field("custom_measurementtable");
    render_measurement_ui(frm);
}



// ======================================================
// RENDER MEASUREMENT UI
// ======================================================
function render_measurement_ui(frm) {

    if (!frm.fields_dict.custom_measurement_ui) return;

    const wrapper = frm.fields_dict.custom_measurement_ui.$wrapper;
    wrapper.empty();

    if (!frm.doc.custom_measurementtable || !frm.doc.custom_measurementtable.length) {
        wrapper.html("<p>No measurements required.</p>");
        return;
    }

    // Force full width
    wrapper.closest(".form-column").css({
        width: "100%",
        maxWidth: "100%",
        flex: "0 0 100%"
    });

    const grid = $(`
        <div style="
            display:grid;
            grid-template-columns: repeat(auto-fit, minmax(520px, 1fr));
            gap:25px;
            margin-top:15px;
        "></div>
    `);

    wrapper.append(grid);

    frm.doc.custom_measurementtable.forEach(row => {

        const type = row.project_type;

        const card = $(`
            <div style="
                background:#ffffff;
                border-radius:12px;
                padding:20px;
                border:1px solid #e4e4e4;
                box-shadow:0 5px 15px rgba(0,0,0,0.05);
            ">
                <h5 style="margin-bottom:18px; font-weight:600;">
                    ${type} - ${row.item_no}
                </h5>
                <div class="fields" style="
                    display:grid;
                    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
                    gap:18px;
                "></div>
            </div>
        `);

        const container = card.find(".fields");

        // ================= WINDOWS =================
        if (type === "Windows") {

            addField(container, row, "room_location", "Room / Location");
            addField(container, row, "window_name", "Name (if appropriate)");
            addField(container, row, "product_width", "Product Width (mm)");
            addField(container, row, "product_height", "Product Height (mm)");
            addField(container, row, "glass", "Glass");
            addField(container, row, "product_name_range", "Product Name / Range");
            addField(container, row, "other_information", "Other Information");
        }

        // ================= DOORS =================
        else if (type === "Internal & External Doors") {

            addField(container, row, "product_width", "Product Width (mm)");
            addField(container, row, "product_height", "Product Height (mm)");
            addField(container, row, "door_type", "Type");
            addField(container, row, "product_name_range", "Product Name / Range");
            addField(container, row, "handles", "Handles");
            addField(container, row, "locks", "Locks");
            addField(container, row, "vents", "Vents");
            addField(container, row, "trims", "Trims");
            addField(container, row, "other_information", "Other Information");
        }

        // ================= ALL OTHER PROJECT TYPES =================
        else {

            addField(container, row, "length", "Length (mm)");
            addField(container, row, "width", "Width (mm)");
            addField(container, row, "height", "Height (mm)");
            addField(container, row, "material", "Material");
            addField(container, row, "finish", "Finish");
            addField(container, row, "structure_type", "Structure / Type");
            addField(container, row, "other_information", "Additional Notes");
        }

        grid.append(card);
    });


    // ======================================================
    // PRODUCTION SAFE SAVE HANDLER
    // ======================================================
    wrapper.off("change").on("change", "input, textarea, select", function () {

        const rowname = $(this).data("name");
        const field = $(this).data("field");
        const value = $(this).val();

        if (!rowname || !field) return;

        frappe.model.set_value(
            "Survey Measurement",   // Child DocType
            rowname,
            field,
            value
        );

        frm.refresh_field("custom_measurementtable");
    });
}



// ======================================================
// FIELD HELPER
// ======================================================
function addField(container, row, field, label) {

    const input = `
        <div style="display:flex; flex-direction:column;">
            <label style="font-size:12px; font-weight:600; margin-bottom:6px;">
                ${label}
            </label>
            <input 
                type="text"
                data-field="${field}"
                data-name="${row.name}"
                value="${row[field] || ''}"
                style="padding:8px; border:1px solid #ccc; border-radius:6px;"
            />
        </div>
    `;

    container.append(input);
}

